"use client";

import { useTRPC } from "@trpc/client";
import { useQuery } from '@tanstack/react-query';

const Todolist = () => {
  const trpc = useTRPC();
  const getTodos = trpc.getTodos.useQuery();
  return (
    <div>{JSON.stringify(getTodos.data)}</div>
  )
}

export default Todolist